from pymongo import MongoClient
from typing import Any


ALLOWED_OPERATORS = {
    "eq": "$eq",
    "ne": "$ne",
    "gt": "$gt",
    "gte": "$gte",
    "lt": "$lt",
    "lte": "$lte",
    "in": "$in",
    "nin": "$nin",
    "regex": "$regex",
    "exists": "$exists",
    "and": "$and",
    "or": "$or",
    "not": "$not",
}

ALLOWED_FIELDS = {"name", "age", "email", "status", "created_at", "category", "price"}


def build_safe_filter(user_filter: dict) -> dict:
    """
    Recursively build a safe MongoDB query from a structured user filter.
    
    Example input:
    {
        "and": [
            {"field": "age", "op": "gte", "value": 18},
            {"field": "status", "op": "eq", "value": "active"},
            {"or": [
                {"field": "category", "op": "in", "value": ["A", "B"]},
                {"field": "price", "op": "lt", "value": 100}
            ]}
        ]
    }
    """
    if not isinstance(user_filter, dict):
        raise ValueError(f"Filter must be a dictionary, got {type(user_filter)}")

    # Handle logical operators (and, or)
    for logic_op in ("and", "or"):
        if logic_op in user_filter:
            if logic_op not in ALLOWED_OPERATORS:
                raise ValueError(f"Operator '{logic_op}' is not allowed")
            conditions = user_filter[logic_op]
            if not isinstance(conditions, list):
                raise ValueError(f"'{logic_op}' value must be a list")
            mongo_op = ALLOWED_OPERATORS[logic_op]
            return {mongo_op: [build_safe_filter(cond) for cond in conditions]}

    # Handle field-level filter: {"field": "age", "op": "gte", "value": 18}
    required_keys = {"field", "op", "value"}
    if not required_keys.issubset(user_filter.keys()):
        raise ValueError(f"Field filter must contain keys: {required_keys}. Got: {set(user_filter.keys())}")

    field = user_filter["field"]
    op = user_filter["op"]
    value = user_filter["value"]

    # Validate field name (whitelist)
    if field not in ALLOWED_FIELDS:
        raise ValueError(f"Field '{field}' is not allowed. Allowed fields: {ALLOWED_FIELDS}")

    # Validate operator (whitelist)
    if op not in ALLOWED_OPERATORS:
        raise ValueError(f"Operator '{op}' is not allowed. Allowed operators: {set(ALLOWED_OPERATORS.keys())}")

    # Validate value types - prevent injection through values
    _validate_value(value)

    mongo_op = ALLOWED_OPERATORS[op]
    return {field: {mongo_op: value}}


def _validate_value(value: Any) -> None:
    """Ensure values don't contain MongoDB operator injection attempts."""
    if isinstance(value, dict):
        for key in value:
            if isinstance(key, str) and key.startswith("$"):
                raise ValueError(f"Operator injection detected in value: '{key}'")
            _validate_value(value[key])
    elif isinstance(value, list):
        for item in value:
            _validate_value(item)
    elif isinstance(value, (str, int, float, bool, type(None))):
        return
    else:
        raise ValueError(f"Unsupported value type: {type(value)}")


class SafeFilterService:
    def __init__(self, connection_string: str = "mongodb://localhost:27017",
                 database: str = "mydb", collection: str = "documents"):
        self.client = MongoClient(connection_string)
        self.db = self.client[database]
        self.collection = self.db[collection]

    def query(self, user_filter: dict, projection: dict | None = None,
              limit: int = 100, skip: int = 0) -> list[dict]:
        """Execute a safe, validated query against MongoDB."""
        safe_filter = build_safe_filter(user_filter)
        print(f"Generated safe MongoDB query: {safe_filter}")

        # Enforce a maximum limit to prevent resource exhaustion
        limit = min(limit, 1000)

        safe_projection = None
        if projection:
            safe_projection = {
                field: 1 for field in projection if field in ALLOWED_FIELDS
            }

        cursor = self.collection.find(
            filter=safe_filter,
            projection=safe_projection
        ).skip(skip).limit(limit)

        return list(cursor)

    def count(self, user_filter: dict) -> int:
        """Count documents matching the safe filter."""
        safe_filter = build_safe_filter(user_filter)
        return self.collection.count_documents(safe_filter)

    def close(self):
        self.client.close()


